import sys
sys.setrecursionlimit(1000000000)


def dfs(i, j, n, c, visited):
    if i == n:
        return True
    visited[i] = True
    for k in range(len(c[i])):
        if visited[c[i][k]] == False:
            if dfs(c[i][k], j, n, c, visited):
                return True
    return False


def main():
    n, m, k = map(int, raw_input().split())
    c = [[] for i in range(n+1)]
    for i in range(m):
        x, y, w = map(int, raw_input().split())
        c[x].append(y)
        c[y].append(x)
    # print c
    count = 0
    for i in range(1, n+1):
        for j in range(len(c[i])):
            visited = [False] * (n+1)
            if dfs(i, c[i][j], n, c, visited):
                count += 1
    print count


if __name__ == '__main__':
    main()
